class Solution {
    public int maximumLength(String s) {
        int maxLen = -1;
        Map<Character, Integer> charCount = new HashMap<>();
        for (char c : s.toCharArray()) {
            charCount.put(c, charCount.getOrDefault(c, 0) + 1);
        }
        for (int count : charCount.values()) {
            if (count >= 3) {
                maxLen = Math.max(maxLen, 1);
            }
        }
        return maxLen;
    }
}
